from debounce import debounce


def test_first_call_always_executes():
    calls = []
    clock = {"t": 0.0}

    @debounce(wait_seconds=5.0, clock=lambda: clock["t"])
    def record(x):
        calls.append(x)
        return x

    assert record(1) == 1
    assert calls == [1]


def test_calls_within_window_are_suppressed():
    calls = []
    clock = {"t": 0.0}

    @debounce(wait_seconds=5.0, clock=lambda: clock["t"])
    def record(x):
        calls.append(x)
        return x

    record(1)
    clock["t"] = 2.0
    result = record(2)
    assert result is None
    assert calls == [1]


def test_call_after_window_executes():
    calls = []
    clock = {"t": 0.0}

    @debounce(wait_seconds=5.0, clock=lambda: clock["t"])
    def record(x):
        calls.append(x)
        return x

    record(1)
    clock["t"] = 6.0
    assert record(2) == 2
    assert calls == [1, 2]


def test_independent_decorated_functions_do_not_share_state():
    calls_a, calls_b = [], []
    clock = {"t": 0.0}

    @debounce(wait_seconds=5.0, clock=lambda: clock["t"])
    def a():
        calls_a.append(1)

    @debounce(wait_seconds=5.0, clock=lambda: clock["t"])
    def b():
        calls_b.append(1)

    a()
    b()
    assert calls_a == [1]
    assert calls_b == [1]

from graph_cycle import has_cycle


def test_empty_graph_has_no_cycle():
    assert has_cycle({}) is False


def test_acyclic_graph():
    g = {"a": ["b"], "b": ["c"], "c": []}
    assert has_cycle(g) is False


def test_simple_cycle():
    g = {"a": ["b"], "b": ["c"], "c": ["a"]}
    assert has_cycle(g) is True


def test_self_loop_is_a_cycle():
    g = {"a": ["a"]}
    assert has_cycle(g) is True


def test_disconnected_components_one_cyclic():
    g = {"a": ["b"], "b": [], "x": ["y"], "y": ["x"]}
    assert has_cycle(g) is True


def test_diamond_shape_no_cycle():
    g = {"a": ["b", "c"], "b": ["d"], "c": ["d"], "d": []}
    assert has_cycle(g) is False


def test_target_only_node_not_in_keys():
    g = {"a": ["b"]}
    assert has_cycle(g) is False
